<?= $this->extend('layouts/panel') ?><?= $this->section('content') ?><?php $errors=session('errors')??[];$labels=['ordered'=>'Sipariş verildi','partial'=>'Kısmi kabul','received'=>'Tamamlandı']; ?><div class="detail-heading"><div><a class="back-link" href="<?= site_url('panel/alislar') ?>">← Alış siparişleri</a><p><span class="badge badge--warning"><?= esc($labels[$order['status']]??$order['status']) ?></span></p></div></div><?php if($errors): ?><div class="alert alert--error"><?= esc(reset($errors)) ?></div><?php endif; ?><section class="form-card info-card"><dl class="info-list"><div><dt>Tedarikçi</dt><dd><?= esc($order['company_name']) ?></dd></div><div><dt>Depo</dt><dd><?= esc($order['warehouse_name']) ?></dd></div><div><dt>Tarih</dt><dd><?= esc(date('d.m.Y',strtotime($order['order_date']))) ?></dd></div><?php if($canViewCost): ?><div><dt>Toplam</dt><dd><?= number_format((float)$order['subtotal'],2,',','.') ?> ₺</dd></div><?php endif; ?></dl></section><section class="panel-card"><form method="post" action="<?= site_url('panel/alislar/'.$order['id'].'/mal-kabul') ?>"><?= csrf_field() ?><div class="table-wrap"><table class="data-table"><thead><tr><th>Ürün</th><th>Sipariş</th><th>Kabul</th><th>Kalan</th><?php if($canViewCost): ?><th>Maliyet</th><?php endif; ?><?php if($canReceive): ?><th>Bu kabul</th><?php endif; ?></tr></thead><tbody><?php foreach($items as $item):$remaining=(float)$item['ordered_quantity']-(float)$item['received_quantity']; ?><tr><td data-label="Ürün"><strong><?= esc($item['product_name_snapshot']) ?></strong><span class="cell-note"><?= esc($item['sku_snapshot']) ?></span></td><td data-label="Sipariş"><?= number_format((float)$item['ordered_quantity'],3,',','.') ?></td><td data-label="Kabul"><?= number_format((float)$item['received_quantity'],3,',','.') ?></td><td data-label="Kalan"><?= number_format($remaining,3,',','.') ?></td><?php if($canViewCost): ?><td data-label="Maliyet"><?= number_format((float)$item['unit_cost'],2,',','.') ?> ₺</td><?php endif; ?><?php if($canReceive): ?><td data-label="Bu kabul"><input class="table-input" name="receive[<?= $item['id'] ?>]" value="0" inputmode="decimal"></td><?php endif; ?></tr><?php endforeach; ?></tbody></table></div><?php if($canReceive): ?><div class="bulk-bar"><div><strong>Mal kabul</strong><small>Stok giriş hareketi oluşturur.</small></div><span></span><button class="button" type="submit">Kabulü kaydet</button></div><?php endif; ?></form></section><?= $this->endSection() ?>
